-- Batch 93 (466-470)
-- 上田 (Ueda), 森本 (Morimoto), 中川 (Nakagawa), 堀 (Hori), 高山 (Takayama)

UPDATE names SET 
  description_zh = '“上”指高处、领先，“田”指农田。意指位于地势较高、水源纯净且产量稳定的上等良田，象征着卓越的地位、丰饶的物质基础与进取的家族精神。上田姓氏展现出一种明快、稳健且极具创造力的意境（因众多活跃于文化艺术界的代表而具有极高的灵性光环），象征着家族具有追求卓越的信念、性格豪爽且能在群体中扮演引领与支撑的关键角色，给人以尊贵、可靠且极具生命活力的深刻印象。',
  description_en = 'Ueda means "upper field," referring to high-quality farmland located in elevated positions with pure water and stable yields. It symbolizes excellent status, material abundance, and an enterprising family spirit. The name showcases a sense of brightness, stability, and creativity (holding a high spiritual halo through various representatives in cultural and artistic fields). It symbolizes a lineage with the conviction to pursue excellence and a bold personality, playing a key role in leading and supporting the community, projecting an image of nobility, reliability, and vitality.',
  meaning_zh = '上等沃田',
  meaning_en = 'Upper Field / High Farm',
  kamon_prompt = 'A circular Japanese kamon featuring the "Ueda-mon" (often variations of the wood sorrel or Katabami) or stylized field patterns with upward-pointing geometric accents within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"上田 晋也","name_jp":"上田 晋也","context":"芸能人 | お笑い芸人（くりぃむしちゅー）、司会者 | 1970年 5月 7日"},{"name":"上田 謙","name_jp":"上田 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"上田 剛史","name_jp":"上田 剛史","context":"スポーツ選手 | 元野球選手 | 1988年 10月 2日"}]'
WHERE romaji = 'ueda' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“森”指广阔，“本”指根源、出发点。意指森林最深处、生命力最为旺盛的本源之地，象征着深不可测的底蕴、顽强的生命意志与扎实的生存基石。森本姓氏展现出一种淳厚、自然且富有哲思的意境，象征着家族具有正直的信念、性格稳健且在学术、体育或传统工艺领域展现出极强的韧性与专注度，给人以斯文、可靠且富有厚重感的深刻印象。',
  description_en = 'Morimoto means "forest root" or "origin of the woods," referring to the deepest part of a forest where life force is most vibrant. It symbolizes fathomless depth, unyielding will, and a solid foundation for survival. The name showcases a sense of sincerity, nature, and philosophical depth. It symbolizes a lineage with honest convictions and a steady personality, demonstrating extraordinary resilience and focus in academia, sports, or traditional crafts, projecting an image of scholarly grace, reliability, and weight.',
  meaning_zh = '森之本源',
  meaning_en = 'Forest Root / Source of Woods',
  kamon_prompt = 'A circular Japanese kamon featuring stylized cluster of three trees (Mori-mon) arranged with roots emphasized in a circular pattern, solid black on a white background.',
  famous_bearers = '[{"name":"森本 稀哲","name_jp":"森本 稀哲","context":"スポーツ選手 | 元野球選手 | 1981年 1月 31日"},{"name":"森本 謙","name_jp":"森本 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"森本 慎太郎","name_jp":"森本 慎太郎","context":"芸能人 | アイドル（SixTONES） | 1997年 7月 15日"}]'
WHERE romaji = 'morimoto' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“中”指核心、枢纽，“川”指江河。意指流经大地的母亲河之中心地带，象征着生命的滋养、交通的汇聚与包容万象的博大胸襟。中川姓氏展现出一种磅礴、动态且极具包容力的意境（因中川翔子等具有跨界影响力的人物而具有极强的灵性色彩），象征着家族具有如流水般不息的创造力、性格直爽且能在群体中扮演连接不同领域的中坚角色，给人以清新、大气且极具感染力的深刻印象。',
  description_en = 'Nakagawa means "central river," referring to the heart of the mother river flowing through the land. It symbolizes the nourishment of life, the convergence of traffic, and a broad mind embracing all things. The name showcases a sense of grandeur, movement, and inclusivity (possessing a strong spiritual color through cross-border influential figures like Shoko Nakagawa). It symbolizes a lineage with ceaseless water-like creativity and a frank personality, playing a pivotal role in connecting different fields, projecting an image of freshness, grandeur, and infectious energy.',
  meaning_zh = '江川之中',
  meaning_en = 'Central River / Middle Stream',
  kamon_prompt = 'A circular Japanese kamon featuring the "Nakagawa-mon" (often variants of three water lines) or stylized river motifs with a central focal point within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"中川 翔子","name_jp":"中川 翔子","context":"芸能人 | タレント、歌手、漫画家（しょこたん） | 1985年 5月 5日"},{"name":"中川 謙","name_jp":"中川 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"中川 家","name_jp":"中川家","context":"芸能人 | お笑いコンビ（剛・礼二） | 1970年/1972年"}]'
WHERE romaji = 'nakagawa' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“堀”指挖掘而成的水渠、护城河。意指人工开凿的清澈水道或家族世代守护的防御要塞，象征着极强的意志力、细致的规划能力与稳固的防御。堀姓氏展现出一种洗练、严谨且极具专业度的意境（因众多活跃于学术与文化界的代表而具有极高的知性光环），象征着家族具有精益求精的工匠精神、性格沉稳且在专业领域拥有坚不可摧的地位，给人以博学、卓越且极具威望的深刻印象。',
  description_en = 'Hori means "moat" or "ditch," referring to man-made clear waterways or defensive fortresses guarded by a family for generations. It symbolizes strong willpower, meticulous planning, and solid defense. The name showcases a sense of refinement, rigor, and professional depth (holding a high intellectual halo through various representatives in academia and culture). It symbolizes a lineage with a meticulous craftsmanship spirit and a steady personality, possessing an indestructible position in specialized fields, projecting an image of erudition, excellence, and prestige.',
  meaning_zh = '守御之渠',
  meaning_en = 'Moat / Defensive Canal',
  kamon_prompt = 'A circular Japanese kamon featuring the specialized "Hori-mon" (often geometric square patterns representing earthworks) or stylized water channel motifs within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"堀 謙","name_jp":"堀 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"堀 未央奈","name_jp":"堀 未央奈","context":"芸能人 | 元アイドル（乃木坂46）、俳優 | 1996年 10月 15日"},{"name":"堀 辰雄","name_jp":"堀 辰雄","context":"文学者 | 小説家（「風立ちぬ」） | 1904年 12月 28日"}]'
WHERE romaji = 'hori' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“高”指崇高、显赫，“山”指山岳。意指高出云表的雄伟峰峦，象征着至高无上的气度、坚不可摧的信念与俯瞰全局的智慧。高山姓氏展现出一种凛然、磅礴且富有英雄色彩的意境，象征着家族具有孤芳自赏的高洁、性格刚毅且在追求理想的道路上绝不妥协，给人以威望极高、沉稳且具有领袖气质的深刻印象。',
  description_en = 'Takayama means "tall mountain," referring to majestic peaks reaching above the clouds. It symbolizes supreme spirit, indestructible conviction, and the wisdom to oversee the big picture. The name showcases a sense of awe, grandeur, and heroic flair. It symbolizes a family with noble solitude and a resolute personality, never compromising in the pursuit of ideals, projecting an image of high prestige, calmness, and leadership.',
  meaning_zh = '云顶之岳',
  meaning_en = 'Tall Mountain / High Summit',
  kamon_prompt = 'A circular Japanese kamon featuring a single, high stylized mountain peak (Yama-gata) often combined with clouds or celestial motifs within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"高山 謙","name_jp":"高山 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"高山 一実","name_jp":"高山 一実","context":"芸能人 | 元アイドル（乃木坂46）、小説家 | 1994年 2月 8日"},{"name":"高山 右近","name_jp":"高山 右近","context":"軍事家 | 戦国時代のキリシタン大名 | 1552年"}]'
WHERE romaji = 'takayama' AND name_part = 'family_name';
